(function(){"use strict";
var C=amsFormsConfig||{},R=C.restUrl,P=C.pageId||0;
function $(s,p){return(p||document).querySelector(s)}
function $$(s,p){return(p||document).querySelectorAll(s)}

var shown={},freqKey="ams_form_freq_";

function init(){
fetch(R+"active?page_id="+P).then(function(r){return r.json()}).then(function(forms){
if(!forms||!forms.length)return;
forms.forEach(function(f){checkAndShow(f)});
}).catch(function(){});}

function checkAndShow(f){
var tc=f.trigger_config||{},tg=f.targeting_config||{};
if(tg.frequency_cap_days){var k=freqKey+f.id,last=localStorage.getItem(k);
if(last&&(Date.now()-parseInt(last,10))<tg.frequency_cap_days*864e5)return;}
if(tg.device){var w=window.innerWidth,d=tg.device;
if(d==="mobile"&&w>768)return;if(d==="desktop"&&w<=768)return;}
if(tc.exit_intent){document.addEventListener("mouseout",function h(e){
if(e.clientY<5&&!shown[f.id]){show(f);shown[f.id]=1;document.removeEventListener("mouseout",h);}
});return;}
if(tc.scroll_percent){var sp=tc.scroll_percent;
window.addEventListener("scroll",function h2(){
var pct=window.scrollY/(document.body.scrollHeight-window.innerHeight)*100;
if(pct>=sp&&!shown[f.id]){show(f);shown[f.id]=1;window.removeEventListener("scroll",h2);}
});return;}
var delay=(tc.delay_seconds||0)*1000;
if(delay>0){setTimeout(function(){if(!shown[f.id]){show(f);shown[f.id]=1;}},delay);}
else{show(f);shown[f.id]=1;}}

function show(f){
recordView(f.id);
var t=f.type||"modal",dc=f.design_config||{};
var wrap=document.createElement("div");wrap.className="ams-form ams-form-"+t;wrap.setAttribute("data-form-id",f.id);
var inner=document.createElement("div");inner.className="ams-form-inner";
if(dc.headline){var h=document.createElement("h2");h.className="ams-form-headline";h.textContent=dc.headline;inner.appendChild(h);}
if(dc.body_text){var p=document.createElement("p");p.className="ams-form-body";p.textContent=dc.body_text;inner.appendChild(p);}
var form=document.createElement("form");form.className="ams-form-fields";form.setAttribute("novalidate","");
(f.fields||[]).forEach(function(fld){
if(fld.type==="hidden"){var hi=document.createElement("input");hi.type="hidden";hi.name=fld.name||fld.type;hi.value=fld.value||"";form.appendChild(hi);return;}
var g=document.createElement("div");g.className="ams-field-group";
if(fld.type==="checkbox"){var cb=document.createElement("input");cb.type="checkbox";cb.name=fld.name||fld.type;cb.id="ams-f-"+f.id+"-"+fld.name;
var lb=document.createElement("label");lb.htmlFor=cb.id;lb.textContent=fld.label||"";g.appendChild(cb);g.appendChild(lb);}
else if(fld.type==="radio"&&fld.options){fld.options.forEach(function(o,i){
var rb=document.createElement("input");rb.type="radio";rb.name=fld.name||fld.type;rb.value=o;rb.id="ams-f-"+f.id+"-"+fld.name+"-"+i;
var rl=document.createElement("label");rl.htmlFor=rb.id;rl.textContent=o;g.appendChild(rb);g.appendChild(rl);});}
else if(fld.type==="dropdown"&&fld.options){var sl=document.createElement("select");sl.name=fld.name||fld.type;
fld.options.forEach(function(o){var op=document.createElement("option");op.value=o;op.textContent=o;sl.appendChild(op);});g.appendChild(sl);}
else if(fld.type==="birthday"){var bd=document.createElement("input");bd.type="date";bd.name=fld.name||"birthday";bd.placeholder=fld.label||"Birthday";g.appendChild(bd);}
else{var inp=document.createElement("input");inp.type=fld.type==="email"?"email":fld.type==="phone"?"tel":"text";
inp.name=fld.name||fld.type;inp.placeholder=fld.label||"";inp.required=!!fld.required;g.appendChild(inp);}
form.appendChild(g);});
if(dc.consent_text){var cg=document.createElement("div");cg.className="ams-field-group ams-consent";
var ccb=document.createElement("input");ccb.type="checkbox";ccb.name="gdpr_consent";ccb.id="ams-consent-"+f.id;ccb.required=true;
var cl=document.createElement("label");cl.htmlFor=ccb.id;cl.textContent=dc.consent_text;cg.appendChild(ccb);cg.appendChild(cl);form.appendChild(cg);}
var btn=document.createElement("button");btn.type="submit";btn.className="ams-form-submit";btn.textContent=dc.button_text||"Subscribe";form.appendChild(btn);
var msg=document.createElement("div");msg.className="ams-form-message";msg.style.display="none";form.appendChild(msg);
form.addEventListener("submit",function(e){e.preventDefault();submitForm(f,form,msg,wrap);});
inner.appendChild(form);
if(t==="modal"||t==="full-page"){var close=document.createElement("button");close.className="ams-form-close";close.innerHTML="&times;";close.type="button";
close.addEventListener("click",function(){wrap.remove();});inner.appendChild(close);
var overlay=document.createElement("div");overlay.className="ams-form-overlay";overlay.addEventListener("click",function(){wrap.remove();});wrap.appendChild(overlay);}
wrap.appendChild(inner);
if(t==="embedded"){var target=$('[data-ams-form="'+f.id+'"]')||$(".ams-embed-target");if(target){target.appendChild(wrap);}else{document.body.appendChild(wrap);}}
else{document.body.appendChild(wrap);}
addStyles(t);}

function submitForm(f,form,msg,wrap){
var fd=new FormData(form),data={form_id:f.id};
(f.fields||[]).forEach(function(fld){var n=fld.name||fld.type;var v=fd.get(n);if(v!==null)data[n]=v;});
if(fd.get("gdpr_consent"))data.gdpr_consent=1;
msg.style.display="none";
fetch(R+"submit",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(data)})
.then(function(r){return r.json()}).then(function(res){
if(res.status==="ok"){var dc=f.design_config||{};msg.textContent=dc.success_message||"Thank you for subscribing!";msg.style.display="block";msg.style.color="#155724";
form.reset();localStorage.setItem(freqKey+f.id,Date.now().toString());
setTimeout(function(){if(f.type!=="embedded")wrap.remove();},3000);}
else{msg.textContent=res.error||"Something went wrong.";msg.style.display="block";msg.style.color="#721c24";}
}).catch(function(){msg.textContent="Network error. Please try again.";msg.style.display="block";msg.style.color="#721c24";});}

function recordView(id){fetch(R+"view",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({form_id:id})}).catch(function(){});}

var stylesAdded=false;
function addStyles(){if(stylesAdded)return;stylesAdded=true;
var s=document.createElement("style");s.textContent=
".ams-form-overlay{position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.5);z-index:99998}"+
".ams-form-modal,.ams-form-full-page{position:fixed;top:0;left:0;right:0;bottom:0;z-index:99999;display:flex;align-items:center;justify-content:center}"+
".ams-form-modal .ams-form-inner{background:#fff;padding:2rem;border-radius:8px;max-width:420px;width:90%;position:relative;z-index:99999;box-shadow:0 4px 24px rgba(0,0,0,.15)}"+
".ams-form-full-page .ams-form-inner{background:#fff;padding:3rem;border-radius:8px;max-width:500px;width:95%;position:relative;z-index:99999}"+
".ams-form-flyout{position:fixed;bottom:20px;right:20px;z-index:99999;animation:ams-slide-up .3s ease}"+
".ams-form-flyout .ams-form-inner{background:#fff;padding:1.5rem;border-radius:8px;box-shadow:0 4px 24px rgba(0,0,0,.15);max-width:360px}"+
".ams-form-sticky-bar{position:fixed;bottom:0;left:0;right:0;z-index:99999;animation:ams-slide-up .3s ease}"+
".ams-form-sticky-bar .ams-form-inner{background:#fff;padding:1rem 2rem;box-shadow:0 -2px 12px rgba(0,0,0,.1);display:flex;align-items:center;gap:12px;flex-wrap:wrap;justify-content:center}"+
".ams-form-embedded .ams-form-inner{padding:1.5rem}"+
".ams-form-headline{margin:0 0 .5rem;font-size:1.25rem}"+
".ams-form-body{margin:0 0 1rem;color:#555}"+
".ams-field-group{margin-bottom:.75rem}"+
".ams-field-group input[type=text],.ams-field-group input[type=email],.ams-field-group input[type=tel],.ams-field-group input[type=date],.ams-field-group select{width:100%;padding:.5rem;border:1px solid #ccc;border-radius:4px;box-sizing:border-box;font-size:.9rem}"+
".ams-consent{display:flex;align-items:flex-start;gap:6px;font-size:.8rem;color:#666}"+
".ams-consent input{margin-top:3px}"+
".ams-form-submit{width:100%;padding:.6rem;background:#2271b1;color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:1rem;transition:background .2s}"+
".ams-form-submit:hover{background:#135e96}"+
".ams-form-close{position:absolute;top:8px;right:12px;background:none;border:none;font-size:1.5rem;cursor:pointer;color:#999;line-height:1}"+
".ams-form-message{margin-top:.75rem;padding:.5rem;border-radius:4px;font-size:.9rem}"+
"@keyframes ams-slide-up{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}";
document.head.appendChild(s);}

if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init);}else{init();}
})();
